import { GoogleGenAI, Type } from "@google/genai";
import type { GeneratedContent } from '../types';

const API_KEY = process.env.API_KEY;

if (!API_KEY) {
  // In a real app, you'd handle this more gracefully.
  // For this context, we assume the key is present.
  console.error("API_KEY environment variable not set.");
}

const ai = new GoogleGenAI({ apiKey: API_KEY });

const contentSchema = {
  type: Type.OBJECT,
  properties: {
    type: { 
      type: Type.STRING,
      description: "Type of content block: 'heading', 'paragraph', 'tip', 'template', or 'benefits'.",
    },
    text: { 
      type: Type.STRING,
      description: "The actual text content for the block."
    },
  },
  required: ['type', 'text']
};

const subPageSchema = {
  type: Type.OBJECT,
  properties: {
    title: { 
      type: Type.STRING,
      description: "A catchy title for the sub-page."
    },
    imageSuggestion: { 
      type: Type.STRING,
      description: "A descriptive suggestion for a relevant image or illustration (e.g., 'A student looking confused at code')."
    },
    content: {
      type: Type.ARRAY,
      items: contentSchema,
      description: "An array of content blocks that make up the page."
    },
    motionStoryboard: { 
      type: Type.STRING,
      description: "A short, creative idea for a motion graphic or animation to be used on this page (e.g., 'A lightbulb icon appears and glows when a tip is shown')."
    },
  },
  required: ['title', 'imageSuggestion', 'content', 'motionStoryboard']
};


const moduleSchema = {
  type: Type.OBJECT,
  properties: {
    skillName: { 
        type: Type.STRING,
        description: "The name of the skill being taught."
    },
    subPages: {
      type: Type.ARRAY,
      items: subPageSchema,
      description: "An array of 5 sub-pages for the learning module."
    },
  },
  required: ['skillName', 'subPages']
};

export const generateSkillContent = async (skillName: string): Promise<GeneratedContent | null> => {
  try {
    const prompt = `
      Generate a complete learning module for the freelance skill: "${skillName}".
      The module must consist of exactly 5 sub-pages, each with unique and valuable content.
      For each sub-page, provide: a unique 'title', an 'imageSuggestion', a 'motionStoryboard', and a rich array of 'content' blocks.

      Content should cover these topics progressively across the 5 pages:
      1.  **Introduction & Getting Started:** What is it, why is it cool, first steps.
      2.  **Core Skills & Beginner Problems:** The fundamental techniques and common hurdles beginners face with step-by-step solutions.
      3.  **Tools & Tips:** Essential software/tools, pro tips, and a practical template students can copy.
      4.  **Growing Your Skill:** How to practice, find inspiration, and build a small project.
      5.  **Freelancing & Benefits:** How to find first clients, build a portfolio, and the real-world benefits (income, confidence, etc.).

      The tone must be friendly, encouraging, and relatable for a student audience. Use simple language.
      Make the content actionable and engaging. Include at least one 'template' and one 'benefits' content block in the entire module.
    `;

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: moduleSchema,
      },
    });

    const jsonString = response.text;
    if (!jsonString) {
      throw new Error("API returned no text.");
    }

    const parsedJson = JSON.parse(jsonString);
    return parsedJson as GeneratedContent;

  } catch (error) {
    console.error("Error generating content:", error);
    return null;
  }
};

import { useState, useCallback } from 'react';

type CopyFn = (text: string) => Promise<boolean>;

function useCopyToClipboard(): [boolean, CopyFn] {
  const [isCopied, setIsCopied] = useState(false);

  const copy: CopyFn = useCallback(async (text) => {
    if (!navigator?.clipboard) {
      console.warn('Clipboard not supported');
      return false;
    }

    try {
      await navigator.clipboard.writeText(text);
      setIsCopied(true);
      setTimeout(() => setIsCopied(false), 2000); // Reset after 2 seconds
      return true;
    } catch (error) {
      console.warn('Copy failed', error);
      setIsCopied(false);
      return false;
    }
  }, []);

  return [isCopied, copy];
}

export default useCopyToClipboard;

