import { GoogleGenAI, Type } from "@google/genai";
import type { GeneratedContent } from '../types';

const getAiClient = () => {
    const API_KEY = process.env.API_KEY;
    if (!API_KEY) {
      throw new Error("API_KEY environment variable not set.");
    }
    return new GoogleGenAI({ apiKey: API_KEY });
}

const contentSchema = {
  type: Type.OBJECT,
  properties: {
    type: { 
      type: Type.STRING,
      description: "Type of content block: 'heading', 'paragraph', 'tip', 'template', or 'benefits'.",
    },
    text: { 
      type: Type.STRING,
      description: "The actual text content for the block."
    },
  },
  required: ['type', 'text']
};

const subPageSchema = {
  type: Type.OBJECT,
  properties: {
    title: { 
      type: Type.STRING,
      description: "A catchy title for the sub-page."
    },
    imageSuggestion: { 
      type: Type.STRING,
      description: "A descriptive suggestion for a relevant image or illustration (e.g., 'A student looking confused at code')."
    },
    content: {
      type: Type.ARRAY,
      items: contentSchema,
      description: "An array of content blocks that make up the page."
    },
    motionStoryboard: { 
      type: Type.STRING,
      description: "A short, creative idea for a motion graphic or animation to be used on this page (e.g., 'A lightbulb icon appears and glows when a tip is shown')."
    },
  },
  required: ['title', 'imageSuggestion', 'content', 'motionStoryboard']
};


const moduleSchema = {
  type: Type.OBJECT,
  properties: {
    skillName: { 
        type: Type.STRING,
        description: "The name of the skill being taught."
    },
    subPages: {
      type: Type.ARRAY,
      items: subPageSchema,
      description: "An array of 5 sub-pages for the learning module."
    },
  },
  required: ['skillName', 'subPages']
};

export const generateSkillContent = async (skillName: string): Promise<GeneratedContent | null> => {
  try {
    const ai = getAiClient();
    const prompt = `
      Ek freelance skill "${skillName}" ke liye complete learning module generate karo, jo Hinglish (Hindi + English) mein ho.
      Ye module Indian students ke liye friendly, aasan aur relatable hona chahiye.
      Ismein total 5 sub-pages hone chahiye, jismein har page par unique content ho.
      Har sub-page ke liye, ek unique 'title', ek 'imageSuggestion', ek 'motionStoryboard', aur alag-alag 'content' blocks ka array do.

      Content in topics par progress karna chahiye:
      1.  **Introduction & Shuruaat:** Ye kya hai, kyu zaroori hai, pehle steps.
      2.  **Main Skills & Beginner Problems:** Basic techniques aur shuruaat mein aane waali problems aur unke solutions.
      3.  **Tools & Tips:** Zaroori software/tools, expert tips, aur ek practical template jise students copy kar sakein.
      4.  **Skill Ko Aage Badhana:** Practice kaise karein, inspiration kahan se lein, aur ek chhota project kaise banayein.
      5.  **Freelancing & Fayde:** Pehle clients kaise dhundein, portfolio kaise banayein, aur asli fayde (paisa, confidence, etc.).

      Poore module mein kam se kam ek 'template' aur ek 'benefits' block zaroor include karna.
    `;

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: moduleSchema,
      },
    });

    const jsonString = response.text;
    if (!jsonString) {
      throw new Error("API returned no text.");
    }

    const parsedJson = JSON.parse(jsonString);
    return parsedJson as GeneratedContent;

  } catch (error) {
    console.error("Error generating content:", error);
    return null;
  }
};

export const analyzeImage = async (prompt: string, imageBase64: string, mimeType: string): Promise<string> => {
    const ai = getAiClient();
    const imagePart = {
      inlineData: {
        data: imageBase64,
        mimeType,
      },
    };
    const textPart = { text: prompt };

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: { parts: [textPart, imagePart] },
    });

    return response.text ?? "Kuch samajh nahi aaya, phir se try karein.";
};

export const analyzeVideo = async (prompt: string, videoBase64: string, mimeType: string): Promise<string> => {
    const ai = getAiClient();
    const videoPart = {
      inlineData: {
        data: videoBase64,
        mimeType,
      },
    };
    const textPart = { text: prompt };

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: { parts: [textPart, videoPart] },
    });

    return response.text ?? "Video ajeeb thi, kuch samajh nahi aaya.";
};

export const animateImage = async (prompt: string, imageBase64: string, mimeType: string, aspectRatio: '16:9' | '9:16', onProgress: (message: string) => void): Promise<string> => {
    const ai = getAiClient();

    onProgress("Video banana shuru ho raha hai...");

    let operation = await ai.models.generateVideos({
      model: 'veo-3.1-fast-generate-preview',
      prompt,
      image: {
        imageBytes: imageBase64,
        mimeType,
      },
      config: {
        numberOfVideos: 1,
        resolution: '720p',
        aspectRatio,
      }
    });

    onProgress("Processing jaari hai... ismein kuch minute lag sakte hain.");

    while (!operation.done) {
      await new Promise(resolve => setTimeout(resolve, 10000));
      operation = await ai.operations.getVideosOperation({ operation });
      const progress = operation.metadata?.progressPercentage ?? 0;
      onProgress(`Video ${Math.round(progress)}% ban chuki hai...`);
    }

    onProgress("Video taiyaar hai!");
    const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
    if (!downloadLink) {
        throw new Error("Video generate ho gayi, par link nahi mila.");
    }

    // The response.body contains the MP4 bytes. You must append an API key when fetching from the download link.
    const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
    const blob = await response.blob();
    return URL.createObjectURL(blob);
};

