import { GoogleGenAI, Type } from "@google/genai";
import type { GeneratedContent } from '../types';

const getAiClient = () => {
    const API_KEY = process.env.API_KEY;
    if (!API_KEY) {
      throw new Error("API_KEY environment variable not set.");
    }
    return new GoogleGenAI({ apiKey: API_KEY });
}

const quizSchema = {
    type: Type.OBJECT,
    properties: {
        type: { type: Type.STRING, description: "The type must be 'quiz'."},
        question: { type: Type.STRING },
        options: { type: Type.ARRAY, items: { type: Type.STRING } },
        correctAnswerIndex: { type: Type.INTEGER },
        explanation: { type: Type.STRING }
    },
    required: ['type', 'question', 'options', 'correctAnswerIndex', 'explanation']
};

const aiChallengeSchema = {
    type: Type.OBJECT,
    properties: {
        type: { type: Type.STRING, description: "The type must be 'aiChallenge'."},
        challenge: { type: Type.STRING },
        toolId: { type: Type.STRING, enum: ['image-analyzer', 'video-analyzer', 'image-animator'] }
    },
    required: ['type', 'challenge', 'toolId']
};

const contentSchema = {
  oneOf: [
    {
      type: Type.OBJECT,
      properties: {
        type: { type: Type.STRING, enum: ['heading', 'paragraph', 'tip', 'template', 'benefits', 'infographic', 'funFact'] },
        text: { type: Type.STRING },
      },
      required: ['type', 'text'],
    },
    quizSchema,
    aiChallengeSchema
  ],
};


const subPageSchema = {
  type: Type.OBJECT,
  properties: {
    title: { 
      type: Type.STRING,
      description: "A catchy title for the sub-page."
    },
    imageSuggestion: { 
      type: Type.STRING,
      description: "A descriptive suggestion for a relevant image or illustration (e.g., 'A student looking confused at code')."
    },
    content: {
      type: Type.ARRAY,
      items: contentSchema,
      description: "An array of various content blocks that make up the page."
    },
    motionStoryboard: { 
      type: Type.STRING,
      description: "A short, creative idea for a motion graphic or animation to be used on this page (e.g., 'A lightbulb icon appears and glows when a tip is shown')."
    },
  },
  required: ['title', 'imageSuggestion', 'content', 'motionStoryboard']
};


const moduleSchema = {
  type: Type.OBJECT,
  properties: {
    skillName: { 
        type: Type.STRING,
        description: "The name of the skill being taught."
    },
    subPages: {
      type: Type.ARRAY,
      items: subPageSchema,
      description: "An array of 10 sub-pages for the learning module."
    },
  },
  required: ['skillName', 'subPages']
};

export const generateSkillContent = async (skillName: string): Promise<GeneratedContent | null> => {
  try {
    const ai = getAiClient();
    const prompt = `
      Ek freelance skill "${skillName}" ke liye ek complete aur engaging learning module generate karo, jo Hinglish (Hindi + English) mein ho.
      Ye module Indian students ke liye friendly, aasan, visually appealing aur relatable hona chahiye.
      Ismein total 10 sub-pages hone chahiye, jisse topic detail mein cover ho.
      Har sub-page ke liye, ek unique 'title', ek 'imageSuggestion', ek 'motionStoryboard', aur alag-alag 'content' blocks ka array do.

      Content blocks mein विविधता (variety) honi chahiye. In types ka istemaal karo: 'heading', 'paragraph', 'tip', 'template', 'benefits', 'infographic', 'funFact', 'quiz', aur 'aiChallenge'.
      - 'infographic' mein text aisa ho jise easily design mein convert kiya ja sake.
      - 'funFact' mein "Kya aap jaante hain?" jaisi interesting baat ho.
      - 'quiz' mein ek sawal, 4 options, sahi answer ka index, aur ek chhota explanation ho.
      - 'aiChallenge' mein ek creative task ho jo user ko app ke AI tool (toolId: 'image-analyzer', 'video-analyzer', or 'image-animator') use karne ke liye encourage kare.

      Poore 10 pages mein in sabhi block types ko kam se kam ek baar zaroor istemaal karna. Content ko interesting aur padhne mein aasan rakho.
    `;

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: moduleSchema,
      },
    });

    const jsonString = response.text;
    if (!jsonString) {
      throw new Error("API returned no text.");
    }

    const parsedJson = JSON.parse(jsonString);
    return parsedJson as GeneratedContent;

  } catch (error) {
    console.error("Error generating content:", error);
    return null;
  }
};

export const analyzeImage = async (prompt: string, imageBase64: string, mimeType: string): Promise<string> => {
    const ai = getAiClient();
    const imagePart = {
      inlineData: {
        data: imageBase64,
        mimeType,
      },
    };
    const textPart = { text: prompt };

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: { parts: [textPart, imagePart] },
    });

    return response.text ?? "Kuch samajh nahi aaya, phir se try karein.";
};

export const analyzeVideo = async (prompt: string, videoBase64: string, mimeType: string): Promise<string> => {
    const ai = getAiClient();
    const videoPart = {
      inlineData: {
        data: videoBase64,
        mimeType,
      },
    };
    const textPart = { text: prompt };

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: { parts: [textPart, videoPart] },
    });

    return response.text ?? "Video ajeeb thi, kuch samajh nahi aaya.";
};

export const animateImage = async (prompt: string, imageBase64: string, mimeType: string, aspectRatio: '16:9' | '9:16', onProgress: (message: string) => void): Promise<string> => {
    const ai = getAiClient();

    onProgress("Video banana shuru ho raha hai...");

    let operation = await ai.models.generateVideos({
      model: 'veo-3.1-fast-generate-preview',
      prompt,
      image: {
        imageBytes: imageBase64,
        mimeType,
      },
      config: {
        numberOfVideos: 1,
        resolution: '720p',
        aspectRatio,
      }
    });

    onProgress("Processing jaari hai... ismein kuch minute lag sakte hain.");

    while (!operation.done) {
      await new Promise(resolve => setTimeout(resolve, 10000));
      operation = await ai.operations.getVideosOperation({ operation });
      const progress = operation.metadata?.progressPercentage ?? 0;
      onProgress(`Video ${Math.round(progress)}% ban chuki hai...`);
    }

    onProgress("Video taiyaar hai!");
    const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
    if (!downloadLink) {
        throw new Error("Video generate ho gayi, par link nahi mila.");
    }

    // The response.body contains the MP4 bytes. You must append an API key when fetching from the download link.
    const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
    const blob = await response.blob();
    return URL.createObjectURL(blob);
};

import React, { useState } from 'react';
import type { QuizBlock as QuizBlockType } from '../types';

interface QuizBlockProps {
  block: QuizBlockType;
}

const QuizBlock: React.FC<QuizBlockProps> = ({ block }) => {
  const [selectedOption, setSelectedOption] = useState<number | null>(null);
  const [isAnswered, setIsAnswered] = useState(false);

  const handleOptionSelect = (index: number) => {
    if (isAnswered) return;
    setSelectedOption(index);
    setIsAnswered(true);
  };

  const getButtonClass = (index: number) => {
    if (!isAnswered) {
      return 'bg-brand-primary hover:bg-brand-primary/80';
    }
    if (index === block.correctAnswerIndex) {
      return 'bg-green-500/80 ring-2 ring-green-400';
    }
    if (index === selectedOption) {
      return 'bg-red-500/80';
    }
    return 'bg-brand-primary opacity-60';
  };

  return (
    <div className="bg-brand-secondary p-4 my-4 rounded-lg border-l-4 border-purple-400">
      <p className="font-semibold text-purple-300 mb-2">🧠 Chalo, Dimaag Lagayein!</p>
      <p className="text-brand-text mb-4">{block.question}</p>
      <div className="grid grid-cols-1 sm:grid-cols-2 gap-2">
        {block.options.map((option, index) => (
          <button
            key={index}
            onClick={() => handleOptionSelect(index)}
            className={`p-3 rounded-md text-left transition-all duration-200 ${getButtonClass(index)}`}
            disabled={isAnswered}
          >
            {option}
          </button>
        ))}
      </div>
      {isAnswered && (
        <div className={`mt-4 p-3 rounded-md ${selectedOption === block.correctAnswerIndex ? 'bg-green-500/20' : 'bg-red-500/20'}`}>
          <p className={`font-bold ${selectedOption === block.correctAnswerIndex ? 'text-green-300' : 'text-red-300'}`}>
            {selectedOption === block.correctAnswerIndex ? 'Bilkul Sahi!' : 'Thoda Galat Ho Gaya'}
          </p>
          <p className="text-brand-text-secondary text-sm mt-1">{block.explanation}</p>
        </div>
      )}
    </div>
  );
};

