import { GoogleGenAI, Type } from "@google/genai";
import type { GeneratedContent } from '../types';

const getAiClient = () => {
    const API_KEY = process.env.API_KEY;
    if (!API_KEY) {
      throw new Error("API_KEY environment variable not set.");
    }
    return new GoogleGenAI({ apiKey: API_KEY });
}

const quizSchema = {
    type: Type.OBJECT, properties: { type: { type: Type.STRING, const: 'quiz' }, question: { type: Type.STRING }, options: { type: Type.ARRAY, items: { type: Type.STRING } }, correctAnswerIndex: { type: Type.INTEGER }, explanation: { type: Type.STRING } }, required: ['type', 'question', 'options', 'correctAnswerIndex', 'explanation']
};
const aiChallengeSchema = {
    type: Type.OBJECT, properties: { type: { type: Type.STRING, const: 'aiChallenge' }, challenge: { type: Type.STRING }, toolId: { type: Type.STRING, enum: ['image-analyzer', 'video-analyzer', 'image-animator'] } }, required: ['type', 'challenge', 'toolId']
};
const pollSchema = {
    type: Type.OBJECT, properties: { type: { type: Type.STRING, const: 'poll' }, question: { type: Type.STRING }, options: { type: Type.ARRAY, items: { type: Type.STRING } } }, required: ['type', 'question', 'options']
};
const qAndASchema = {
    type: Type.OBJECT, properties: { type: { type: Type.STRING, const: 'qAndA' }, question: { type: Type.STRING }, answer: { type: Type.STRING } }, required: ['type', 'question', 'answer']
};
const expertSaysSchema = {
    type: Type.OBJECT, properties: { type: { type: Type.STRING, const: 'expertSays' }, quote: { type: Type.STRING }, expertName: { type: Type.STRING } }, required: ['type', 'quote', 'expertName']
};
const mythBusterSchema = {
    type: Type.OBJECT, properties: { type: { type: Type.STRING, const: 'mythBuster' }, myth: { type: Type.STRING }, reality: { type: Type.STRING } }, required: ['type', 'myth', 'reality']
};
const doAndDontSchema = {
    type: Type.OBJECT, properties: { type: { type: Type.STRING, const: 'doAndDont' }, dos: { type: Type.ARRAY, items: { type: Type.STRING } }, donts: { type: Type.ARRAY, items: { type: Type.STRING } } }, required: ['type', 'dos', 'donts']
};
const shockingFactSchema = {
    type: Type.OBJECT, properties: { type: { type: Type.STRING, const: 'shockingFact' }, fact: { type: Type.STRING } }, required: ['type', 'fact']
};
const ideaCornerSchema = {
    type: Type.OBJECT, properties: { type: { type: Type.STRING, const: 'ideaCorner' }, prompt: { type: Type.STRING } }, required: ['type', 'prompt']
};
const basicTextBlockSchema = {
    type: Type.OBJECT, properties: { type: { type: Type.STRING, enum: ['heading', 'paragraph', 'tip', 'template', 'benefits', 'infographic', 'funFact'] }, text: { type: Type.STRING } }, required: ['type', 'text']
};

const contentSchema = {
  oneOf: [ basicTextBlockSchema, quizSchema, aiChallengeSchema, pollSchema, qAndASchema, expertSaysSchema, mythBusterSchema, doAndDontSchema, shockingFactSchema, ideaCornerSchema ],
};

const subPageSchema = {
  type: Type.OBJECT,
  properties: {
    title: { type: Type.STRING, description: "A catchy title for the sub-page." },
    imageSuggestion: { type: Type.STRING, description: "A descriptive suggestion for a relevant image or illustration (e.g., 'A student looking confused at code')." },
    content: { type: Type.ARRAY, items: contentSchema, description: "An array of various content blocks that make up the page." },
    motionStoryboard: { type: Type.STRING, description: "A short, creative idea for a motion graphic or animation to be used on this page (e.g., 'A lightbulb icon appears and glows when a tip is shown')." },
  },
  required: ['title', 'imageSuggestion', 'content', 'motionStoryboard']
};

const moduleSchema = {
  type: Type.OBJECT,
  properties: {
    skillName: { type: Type.STRING, description: "The name of the skill being taught." },
    subPages: { type: Type.ARRAY, items: subPageSchema, description: "An array of 10 sub-pages for the learning module." },
  },
  required: ['skillName', 'subPages']
};

export const generateSkillContent = async (skillName: string): Promise<GeneratedContent | null> => {
  try {
    const ai = getAiClient();
    const prompt = `
      Ek freelance skill "${skillName}" ke liye ek અત્યંત engaging (extremely engaging) learning module generate karo, jo Hinglish (Hindi + English) mein ho.
      Ye module Indian students ke liye super fun, visual, aur relatable hona chahiye. Plain text se bacho.
      Total 10 detailed sub-pages generate karo.

      Har page ko in sabhi interactive elements se bhar do. Har page par kam se kam 5-6 alag-alag block types istemaal karo. Bohot variety chahiye:
      - 'heading', 'paragraph', 'tip', 'template', 'benefits', 'infographic', 'funFact'
      - 'quiz': Interesting sawal, 4 options, sahi jawab, aur explanation.
      - 'aiChallenge': Creative task jo user ko app ke AI tools ('image-analyzer', 'video-analyzer', 'image-animator') use karne ke liye challenge kare.
      - 'poll': Ek interesting question jiske multiple options ho.
      - 'qAndA': Common student doubts ko solve karo.
      - 'expertSays': Ek virtual expert ka quote.
      - 'mythBuster': Skill se jude myths ko bust karo.
      - 'doAndDont': Quick tips in a list format.
      - 'shockingFact': Ek dum unexpected fact.
      - 'ideaCorner': User ko kuch naya sochne ke liye inspire karo.

      Content ko friendly, encouraging, aur bohot hi zyada interesting banao. Har page ek naya adventure lagna chahiye.
    `;

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: moduleSchema,
      },
    });

    const jsonString = response.text;
    if (!jsonString) { throw new Error("API returned no text."); }

    const parsedJson = JSON.parse(jsonString);
    return parsedJson as GeneratedContent;

  } catch (error) {
    console.error("Error generating content:", error);
    return null;
  }
};

export const analyzeImage = async (prompt: string, imageBase64: string, mimeType: string): Promise<string> => {
    const ai = getAiClient();
    const imagePart = { inlineData: { data: imageBase64, mimeType } };
    const textPart = { text: prompt };
    const response = await ai.models.generateContent({ model: 'gemini-3-pro-preview', contents: { parts: [textPart, imagePart] } });
    return response.text ?? "Kuch samajh nahi aaya, phir se try karein.";
};

export const analyzeVideo = async (prompt: string, videoBase64: string, mimeType: string): Promise<string> => {
    const ai = getAiClient();
    const videoPart = { inlineData: { data: videoBase64, mimeType } };
    const textPart = { text: prompt };
    const response = await ai.models.generateContent({ model: 'gemini-3-pro-preview', contents: { parts: [textPart, videoPart] } });
    return response.text ?? "Video ajeeb thi, kuch samajh nahi aaya.";
};

export const animateImage = async (prompt: string, imageBase64: string, mimeType: string, aspectRatio: '16:9' | '9:16', onProgress: (message: string) => void): Promise<string> => {
    const ai = getAiClient();
    onProgress("Video banana shuru ho raha hai...");
    let operation = await ai.models.generateVideos({ model: 'veo-3.1-fast-generate-preview', prompt, image: { imageBytes: imageBase64, mimeType }, config: { numberOfVideos: 1, resolution: '720p', aspectRatio } });
    onProgress("Processing jaari hai... ismein kuch minute lag sakte hain.");
    while (!operation.done) {
      await new Promise(resolve => setTimeout(resolve, 10000));
      operation = await ai.operations.getVideosOperation({ operation });
      const progress = operation.metadata?.progressPercentage ?? 0;
      onProgress(`Video ${Math.round(progress)}% ban chuki hai...`);
    }
    onProgress("Video taiyaar hai!");
    const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
    if (!downloadLink) { throw new Error("Video generate ho gayi, par link nahi mila."); }
    const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
    const blob = await response.blob();
    return URL.createObjectURL(blob);
};

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { useParams, Link } from 'react-router-dom';
import { SKILLS } from '../constants';
import type { GeneratedContent, ContentBlock, SubPage, QuizBlock as QuizBlockType, AiChallengeBlock as AiChallengeBlockType, PollBlock as PollBlockType, QAndABlock as QAndABlockType, ExpertSaysBlock as ExpertSaysBlockType, MythBusterBlock as MythBusterBlockType, DoAndDontBlock as DoAndDontBlockType, ShockingFactBlock as ShockingFactBlockType, IdeaCornerBlock as IdeaCornerBlockType } from '../types';
import { generateSkillContent } from '../services/geminiService';
import Loading from '../components/Loading';
import ErrorMessage from '../components/ErrorMessage';
import CopyButton from '../components/CopyButton';
import QuizBlock from '../components/QuizBlock';
import AiChallengeBlock from '../components/AiChallengeBlock';
import PollBlock from '../components/PollBlock';
import QAndABlock from '../components/QAndABlock';
import ExpertSaysBlock from '../components/ExpertSaysBlock';
import MythBusterBlock from '../components/MythBusterBlock';
import DoAndDontBlock from '../components/DoAndDontBlock';
import ShockingFactBlock from '../components/ShockingFactBlock';
import IdeaCornerBlock from '../components/IdeaCornerBlock';

const CategoryPage: React.FC = () => {
  const { categoryId } = useParams<{ categoryId: string }>();
  const [content, setContent] = useState<GeneratedContent | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [currentPage, setCurrentPage] = useState(0);

  const skill = useMemo(() => SKILLS.find(s => s.id === categoryId), [categoryId]);

  const fetchContent = useCallback(async () => {
    if (!skill) {
        setError("Invalid skill category.");
        setLoading(false);
        return;
    }
    setLoading(true);
    setError(null);
    try {
      const generatedData = await generateSkillContent(skill.name);
      if (generatedData) {
        setContent(generatedData);
      } else {
        throw new Error("Content generate nahi ho paaya. AI guru shayad busy hain.");
      }
    } catch (e: any) {
      setError(e.message || "An unknown error occurred.");
    } finally {
      setLoading(false);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [skill]);

  useEffect(() => {
    fetchContent();
    setCurrentPage(0); // Reset to first page on new category
  }, [fetchContent]);

  const handleNext = () => {
    if (content && currentPage < content.subPages.length - 1) {
      setCurrentPage(currentPage + 1);
    }
  };

  const handlePrev = () => {
    if (currentPage > 0) {
      setCurrentPage(currentPage - 1);
    }
  };

  if (!skill) {
    return (
        <div className="text-center">
            <h2 className="text-2xl font-bold text-red-400">Skill nahi mili!</h2>
            <Link to="/" className="text-brand-accent hover:underline mt-4 inline-block">Home par wapas jaayein</Link>
        </div>
    );
  }

  if (loading) {
    return <Loading message={`Aapka ${skill.name} course ban raha hai...`} />;
  }

  if (error) {
    return <ErrorMessage message={error} onRetry={fetchContent} />;
  }

  if (!content || !content.subPages || content.subPages.length === 0) {
    return <ErrorMessage message="Iss skill ke liye koi content nahi mila." onRetry={fetchContent} />;
  }

  const currentSubPage: SubPage = content.subPages[currentPage];
  const progressPercentage = ((currentPage + 1) / content.subPages.length) * 100;

  const renderContentBlock = (block: ContentBlock, index: number) => {
    switch (block.type) {
      case 'heading':
        return <h2 key={index} className="text-2xl font-bold text-brand-text mt-6 mb-3">{block.text}</h2>;
      case 'paragraph':
        return <p key={index} className="text-brand-text-secondary leading-relaxed mb-4">{block.text}</p>;
      case 'tip':
        return (
          <div key={index} className="bg-brand-secondary p-4 rounded-lg border-l-4 border-amber-400 my-4">
            <p className="font-semibold text-amber-300 mb-1">💡 Expert Salah</p>
            <p className="text-brand-text-secondary">{block.text}</p>
          </div>
        );
      case 'template':
        return (
          <div key={index} className="relative bg-brand-primary p-4 rounded-lg my-4 border border-brand-secondary">
            <p className="font-semibold text-cyan-300 mb-2">📋 Template</p>
            <pre className="text-sm text-brand-text whitespace-pre-wrap font-mono">{block.text}</pre>
            <CopyButton textToCopy={block.text} />
          </div>
        );
      case 'benefits':
        return (
          <div key={index} className="bg-gradient-to-br from-green-500/10 to-emerald-500/10 p-4 rounded-lg border-l-4 border-emerald-400 my-4">
              <p className="font-semibold text-emerald-300 mb-1">🚀 Aapka Inaam</p>
              <p className="text-brand-text-secondary">{block.text}</p>
          </div>
        );
      case 'infographic':
        return (
          <div key={index} className="bg-sky-500/10 p-4 rounded-lg border-l-4 border-sky-400 my-4">
              <p className="font-semibold text-sky-300 mb-1">📊 Infographic Idea</p>
              <p className="text-brand-text-secondary italic">{block.text}</p>
          </div>
        );
      case 'funFact':
        return (
          <div key={index} className="bg-rose-500/10 p-4 rounded-lg border-l-4 border-rose-400 my-4">
              <p className="font-semibold text-rose-300 mb-1">🤯 Kya Aap Jaante Hain?</p>
              <p className="text-brand-text-secondary">{block.text}</p>
          </div>
        );
      case 'quiz':
          return <QuizBlock key={index} block={block as QuizBlockType} />;
      case 'aiChallenge':
          return <AiChallengeBlock key={index} block={block as AiChallengeBlockType} />;
      case 'poll':
          return <PollBlock key={index} block={block as PollBlockType} />;
      case 'qAndA':
          return <QAndABlock key={index} block={block as QAndABlockType} />;
      case 'expertSays':
          return <ExpertSaysBlock key={index} block={block as ExpertSaysBlockType} />;
      case 'mythBuster':
          return <MythBusterBlock key={index} block={block as MythBusterBlockType} />;
      case 'doAndDont':
          return <DoAndDontBlock key={index} block={block as DoAndDontBlockType} />;
      case 'shockingFact':
          return <ShockingFactBlock key={index} block={block as ShockingFactBlockType} />;
      case 'ideaCorner':
          return <IdeaCornerBlock key={index} block={block as IdeaCornerBlockType} />;
      default:
        return null;
    }
  };

  return (
    <div className="container mx-auto max-w-3xl animate-fadeIn">
        <Link to="/" className="text-brand-accent hover:underline mb-4 inline-block">&larr; Sabhi skills par wapas</Link>
      <div className="bg-brand-secondary rounded-2xl shadow-lg overflow-hidden">
        <div className="p-6 md:p-8">
            <div className="w-full bg-brand-primary rounded-full h-2.5 mb-6">
                <div className="bg-brand-accent h-2.5 rounded-full" style={{ width: `${progressPercentage}%`, transition: 'width 0.5s ease-in-out' }}></div>
            </div>

            <div key={currentPage} className="animate-fadeIn">
                <h1 className="text-3xl md:text-4xl font-extrabold text-brand-text mb-2">{currentSubPage.title}</h1>
                <p className="text-brand-text-secondary text-sm mb-4 italic">Motion ka idea: {currentSubPage.motionStoryboard}</p>
                <img 
                    src={`https://picsum.photos/seed/${encodeURIComponent(currentSubPage.imageSuggestion)}/800/400`} 
                    alt={currentSubPage.imageSuggestion}
                    className="w-full h-48 object-cover rounded-lg mb-6"
                />

                {currentSubPage.content.map(renderContentBlock)}
            </div>
        </div>
      </div>

      <div className="flex justify-between items-center mt-6">
        <button 
          onClick={handlePrev} 
          disabled={currentPage === 0}
          className="px-6 py-3 bg-brand-secondary rounded-lg font-semibold disabled:opacity-50 disabled:cursor-not-allowed hover:bg-brand-secondary/80 transition-colors"
        >
          Pichla
        </button>
        <span className="text-brand-text-secondary font-medium">Page {currentPage + 1} / {content.subPages.length}</span>
        <button 
          onClick={handleNext} 
          disabled={currentPage === content.subPages.length - 1}
          className="px-6 py-3 bg-brand-accent rounded-lg font-semibold disabled:opacity-50 disabled:cursor-not-allowed hover:bg-brand-accent-light transition-colors"
        >
          Agla
        </button>
      </div>
    </div>
  );
};

export default CategoryPage;

import React, { useState } from 'react';
import type { PollBlock as PollBlockType } from '../types';

interface PollBlockProps {
  block: PollBlockType;
}

const PollBlock: React.FC<PollBlockProps> = ({ block }) => {
  const [voted, setVoted] = useState(false);
  // Simulate some initial random percentages for visual effect
  const [percentages] = useState(() => {
    let remaining = 100;
    const results = [];
    for (let i = 0; i < block.options.length - 1; i++) {
      const vote = Math.floor(Math.random() * (remaining / 2));
      results.push(vote);
      remaining -= vote;
    }
    results.push(remaining);
    return results.sort((a, b) => b - a); // Sort for visual appeal
  });

  return (
    <div className="bg-brand-secondary p-4 my-4 rounded-lg border-l-4 border-cyan-400">
      <p className="font-semibold text-cyan-300 mb-2">📊 Aapki Kya Raay Hai?</p>
      <p className="text-brand-text mb-4">{block.question}</p>
      <div className="space-y-2">
        {block.options.map((option, index) => (
          <button
            key={index}
            onClick={() => setVoted(true)}
            disabled={voted}
            className="w-full text-left p-2 rounded-md bg-brand-primary transition-all duration-300 group overflow-hidden relative"
          >
            <div 
                className="absolute top-0 left-0 h-full bg-cyan-500/30 transition-all duration-500 ease-out"
                style={{ width: voted ? `${percentages[index]}%` : '0%' }}
            />
            <div className="relative flex justify-between">
                <span>{option}</span>
                {voted && <span className="font-bold">{percentages[index]}%</span>}
            </div>
          </button>
        ))}
      </div>
    </div>
  );
};

